def normalize_to_srgb(image: Image.Image) -> Image.Image:
    icc = image.info.get("icc_profile")
    if not icc:
        return image
    try:
        input_profile = ImageCms.ImageCmsProfile(io.BytesIO(icc))
        srgb_profile = ImageCms.createProfile("sRGB")
        mode = "RGBA" if image.mode == "RGBA" else "RGB"
        return ImageCms.profileToProfile(image, input_profile, srgb_profile, outputMode=mode)
    except Exception:
        return image


def crop_to_content(img: Image.Image, padding: int = 4) -> Image.Image:
    arr = np.array(img)
    alpha = arr[:, :, 3]
    ys, xs = np.where(alpha > 10)
    if len(xs) == 0:
        return img
    x0, x1 = max(xs.min() - padding, 0), min(xs.max() + padding, img.width)
    y0, y1 = max(ys.min() - padding, 0), min(ys.max() + padding, img.height)
    return img.crop((x0, y0, x1, y1))


ALPHA_FLOOR = 1
# Explicit sRGB tag written into every exported PNG. Procreate exports tag
# their files as sRGB (a plain 'sRGB' chunk); Pillow's plain PNG save writes
# no color-space info at all. Without any tag, Apple's color management on
# wide-gamut (P3) screens can render the file slightly lighter/less saturated
# than the same pixel values with an explicit sRGB declaration - this is what
# shows up as a "washed out" pattern on Mac/iPhone even though the raw pixel
# values are correct.
SRGB_ICC_PROFILE = ImageCms.ImageCmsProfile(ImageCms.createProfile("sRGB")).tobytes()
# Very conservative final cleanup: only pixels that are virtually invisible
# are removed. This keeps soft watercolor edges intact while preventing a
# faint fringe at extreme zoom.
FINAL_ALPHA_THRESHOLD = 3


def bleed_rgb_into_transparency(img: Image.Image) -> Image.Image:
    """Fill hidden RGB in transparent pixels from the nearest visible pixel.

    PNGs often contain white, grey, or black RGB values under fully transparent
    pixels. Resizing and rotation sample those hidden values and create a halo.
    Filling them with the nearest motif colour prevents that contamination while
    leaving the alpha channel completely unchanged.
    """
    arr = np.asarray(img.convert("RGBA")).copy()
    alpha = arr[:, :, 3]
    visible = alpha > ALPHA_FLOOR
    if not visible.any():
        return img.convert("RGBA")

    # For every transparent pixel, get the nearest visible-pixel coordinates.
    _, indices = distance_transform_edt(~visible, return_indices=True)
    nearest_y, nearest_x = indices
    transparent = ~visible
    for channel in range(3):
        source = arr[:, :, channel]
        filled = source[nearest_y, nearest_x]
        source[transparent] = filled[transparent]
        arr[:, :, channel] = source

    # Keep original alpha exactly; only hidden RGB has changed.
    arr[:, :, 3] = alpha
    return Image.fromarray(arr, "RGBA")


def clean_after_transform(img: Image.Image) -> Image.Image:
    """Remove only virtually invisible edge pixels and clear hidden RGB.

    The threshold is intentionally tiny so the soft watercolor edge remains
    intact. Pixels with meaningful opacity are never changed.
    """
    arr = np.asarray(img.convert("RGBA")).copy()
    alpha = arr[:, :, 3]
    invisible = alpha <= FINAL_ALPHA_THRESHOLD
    arr[invisible, :3] = 0
    arr[invisible, 3] = 0
    return Image.fromarray(arr, "RGBA")


def decontaminate_white_matte(img: Image.Image, bg=(255, 255, 255)) -> Image.Image:
    """Remove white bled into every partially-transparent pixel, not just fully invisible ones.

    Source PNGs exported from Procreate are typically flattened over a white
    canvas before transparency is extracted. Every pixel that is not fully
    opaque - the soft outer edge, but also any spot where two watercolor
    strokes overlap inside the motif - still carries a blend with that white
    background baked into its RGB. That is what shows up as a pale/washed
    halo, both around the silhouette and inside overlaps. This undoes the
    blend so the true stroke color shows through, without changing alpha or
    softness at all - so thin details stay exactly as thin as they were.
    """
    arr = np.asarray(img.convert("RGBA")).astype(np.float32)
    alpha = arr[:, :, 3] / 255.0
    partial = (alpha > 0) & (alpha < 1)
    if not partial.any():
        return img.convert("RGBA")
    safe_alpha = np.where(partial, alpha, 1.0)
    bg_arr = np.array(bg, dtype=np.float32)
    for c in range(3):
        observed = arr[:, :, c]
        true_color = (observed - (1.0 - safe_alpha) * bg_arr[c]) / safe_alpha
        arr[:, :, c] = np.where(partial, true_color, observed)
    arr[:, :, :3] = np.clip(arr[:, :, :3], 0, 255)
    return Image.fromarray(arr.astype(np.uint8), "RGBA")


def suppress_resample_ringing(sharp_img: Image.Image, safe_img: Image.Image, window: int = 3) -> Image.Image:
    """Kill bright/dark overshoot at hard internal edges from LANCZOS/BICUBIC.

    A sharp resample filter can "ring" at a hard internal color boundary
    (e.g. leaf overlapping the pear body, both fully opaque) - it briefly
    overshoots brighter or darker than either original color. That is the
    thin, sharp, lighter line visible inside a motif after rotating/resizing.
    A linear resample of the same source can't overshoot like that, so it's
    used as a safe reference: the sharp result is clipped, pixel by pixel, to
    the local min/max range of the safe result. Anywhere the sharp filter
    agrees with the plausible range nothing changes; only the overshoot spike
    gets pulled back down - genuine soft watercolor edges are untouched.
    """
    sharp = np.asarray(sharp_img.convert("RGBA")).astype(np.float32)
    safe = np.asarray(safe_img.convert("RGBA")).astype(np.float32)
    lo = minimum_filter(safe, size=(window, window, 1))
    hi = maximum_filter(safe, size=(window, window, 1))
    clipped = np.clip(sharp, lo, hi)
    return Image.fromarray(clipped.astype(np.uint8), "RGBA")


RINGING_SUPPRESSION_MIN_SCALE = 0.4
# Below this scale factor, the BILINEAR "safe" reference used for ringing
# suppression becomes so much softer than LANCZOS that clamping to its
# min/max range drags the sharp result down toward BILINEAR quality - i.e.
# it blurs the motif instead of just removing overshoot. Ringing is barely
# visible at strong downscale anyway (LANCZOS already averages enough
# source pixels per output pixel), so the clamp is simply skipped there and
# the halo-safe premultiplied LANCZOS result is used as-is.


def motif_scale_needs_ringing_suppression(src_size, target_size) -> bool:
    """Single source of truth for the resize+rotate ringing-suppression decision.

    Computed once from the motif's original size vs. its final placed size,
    so resize_alpha_safe and rotate_alpha_safe make the same call instead of
    each deciding independently (which previously let rotation re-blur a
    motif that resize had already correctly left sharp).
    """
    src_w, src_h = src_size
    target_w, target_h = target_size
    if not src_w or not src_h:
        return True
    scale = max(target_w / src_w, target_h / src_h)
    return scale >= RINGING_SUPPRESSION_MIN_SCALE


def resize_alpha_safe(img, size, resample=Image.Resampling.LANCZOS, suppress_ringing=None):
    """Resize in premultiplied-alpha mode to avoid light or dark halos."""
    rgba = img.convert("RGBA")
    premultiplied = rgba.convert("RGBa")
    resized = premultiplied.resize(size, resample=resample).convert("RGBA")

    if suppress_ringing is None:
        suppress_ringing = motif_scale_needs_ringing_suppression(img.size, size)

    if not suppress_ringing:
        return clean_after_transform(resized)

    safe = premultiplied.resize(size, resample=Image.Resampling.BILINEAR).convert("RGBA")
    resized = suppress_resample_ringing(resized, safe)
    return clean_after_transform(resized)


def rotate_alpha_safe(img, angle, resample=Image.Resampling.BICUBIC, suppress_ringing=True):
    """Rotate in premultiplied-alpha mode so transparent RGB cannot bleed."""
    rgba = img.convert("RGBA")
    premultiplied = rgba.convert("RGBa")
    rotated = premultiplied.rotate(
        angle, expand=True, resample=resample, fillcolor=(0, 0, 0, 0)
    ).convert("RGBA")

    if not suppress_ringing:
        return clean_after_transform(rotated)

    safe = premultiplied.rotate(
        angle, expand=True, resample=Image.Resampling.BILINEAR, fillcolor=(0, 0, 0, 0)
    ).convert("RGBA")
    rotated = suppress_resample_ringing(rotated, safe)
    return clean_after_transform(rotated)


def place_motif_on_canvas(canvas, motif, slot, canvas_size=CANVAS_SIZE):
    target_dim = slot["width"]
    longer_side = max(motif.width, motif.height)
    scale = target_dim / longer_side

    # Ringing suppression is decided purely by the overall scale factor
    # (rotating first doesn't change how much the motif ultimately shrinks).
    suppress_ringing = scale >= RINGING_SUPPRESSION_MIN_SCALE

    # Most calibrated templates mirror the source before applying the fixed
    # template rotation. For special slots such as Snails S01, mirroring must
    # be independent from the angle: rotate first, then mirror the finished
    # placement, so toggling the mirror checkbox cannot visually cancel the
    # intended 34-degree tilt.
    #
    # Rotation happens here, on the full-resolution motif, before any
    # downscaling - rotating a small, already-shrunk image throws away detail
    # it can't recover, while rotating at full size and shrinking afterwards
    # keeps the LANCZOS downscale as the only real quality-limiting step.
    # Rotating then scaling lands on the same final size as scaling then
    # rotating (the two operations commute), so template calibration is
    # unaffected.
    if slot.get("flip_after_rotation", False):
        rotated_full = rotate_alpha_safe(motif, slot["rotation"], resample=Image.Resampling.BICUBIC)
        if slot.get("flip"):
            rotated_full = rotated_full.transpose(Image.Transpose.FLIP_LEFT_RIGHT)
    else:
        working = motif
        if slot.get("flip"):
            working = working.transpose(Image.Transpose.FLIP_LEFT_RIGHT)
        rotated_full = rotate_alpha_safe(working, slot["rotation"], resample=Image.Resampling.BICUBIC)

    final_w = max(1, round(rotated_full.width * scale))
    final_h = max(1, round(rotated_full.height * scale))
    rotated = resize_alpha_safe(
        rotated_full, (final_w, final_h), Image.Resampling.LANCZOS, suppress_ringing=suppress_ringing
    )
    rw, rh = rotated.size
    cx, cy = slot["x"], slot["y"]
    paste_x = cx - rw // 2
    paste_y = cy - rh // 2
    overlay = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
    overlay.alpha_composite(rotated, (paste_x, paste_y))
    canvas = Image.alpha_composite(canvas.convert("RGBA"), overlay)
    offsets = []
    if paste_x < 0: offsets.append((canvas_size, 0))
    if paste_x + rw > canvas_size: offsets.append((-canvas_size, 0))
    if paste_y < 0: offsets.append((0, canvas_size))
    if paste_y + rh > canvas_size: offsets.append((0, -canvas_size))
    if paste_x < 0 and paste_y < 0: offsets.append((canvas_size, canvas_size))
    if paste_x + rw > canvas_size and paste_y < 0: offsets.append((-canvas_size, canvas_size))
    if paste_x < 0 and paste_y + rh > canvas_size: offsets.append((canvas_size, -canvas_size))
    if paste_x + rw > canvas_size and paste_y + rh > canvas_size: offsets.append((-canvas_size, -canvas_size))
    for dx, dy in offsets:
        overlay = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
        overlay.alpha_composite(rotated, (paste_x + dx, paste_y + dy))
        canvas = Image.alpha_composite(canvas.convert("RGBA"), overlay)
    return canvas


def render_template_schematic(template, sample_motif, size=260, canvas_size=CANVAS_SIZE):
    """Real preview: places a sample motif on all slots so you can
    actually see the template layout, not just empty circles."""
    canvas = Image.new("RGBA", (canvas_size, canvas_size), (0, 0, 0, 0))
    for slot in template["main"] + template["secondary"]:
        canvas = place_motif_on_canvas(canvas, sample_motif, slot, canvas_size)
    bg = Image.new("RGBA", canvas.size, (250, 250, 250, 255))
    bg.paste(canvas, (0, 0), canvas)
    return bg.resize((size, size), Image.Resampling.LANCZOS)


def make_sample_motif(size=300):
    """Generates a simple, generic placeholder motif (leaf shape) for the preview."""
    img = Image.new("RGBA", (size, size), (0, 0, 0, 0))
    draw = ImageDraw.Draw(img)
    draw.ellipse([size*0.2, size*0.1, size*0.8, size*0.9], fill=(162, 181, 162, 255))
    draw.ellipse([size*0.35, size*0.3, size*0.65, size*0.6], fill=(250, 250, 250, 255))
    return img


